var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"결국 다른 사람들도 찾아가봤지만, 키울 여건이 마땅해 보이는 사람이 잘 없네.","JPN":"他の人にも当たってみたけど、ちょうどいい条件の人はいないね。","ENG":"We tried some other people, but none of them can afford a cat right now.","TWN":"結果還是沒找到合適養貓的人選…"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네. 역시 완벽한 주인을 찾아주는 건 힘든 일인가봐요.","JPN":"はい。やっぱり完璧な里親さんを見つけるのは難しいですね。","ENG":"No, it's definitely not easy finding the perfect owner for him.","TWN":"對啊，要替牠找到完美主人真是不容易呢！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본래 완벽한 조건을 찾기란 존재하지 않는 법이다, 호진 대원.","JPN":"本来完璧に条件を満たす人など存在しないものだ、マユミ隊員。","ENG":"There's no such thing as perfection, Operative Hojin.","TWN":"鎬眞隊員，完美本來就不存在於這個世界上。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"전장의 상황이 항상 군인의 마음을 따라주지 않는 법.","JPN":"戦場の状況が、常に思いどおりにはいくとは限らない。","ENG":"The situation on the battlefield doesn't always go the way you want it.","TWN":"戰場上的事也是千變萬化，無法預測。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"중요한 건 그 상황에 자신이 어떻게 대처하느냐다. 모든 건 마음먹기에 달린 것이지.","JPN":"大事なのは、その状況に自分がどのように対処するかだ。\\nすべては気持ち次第である。","ENG":"You have to take it as it comes. Everything depends on your way of thinking.","TWN":"重點是，在那個當下你會如何反應，關鍵在於你的決心。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와, 소림아. 너 엄청 굉장하다.","JPN":"わあ、ミズキちゃん……カッコいい。","ENG":"Whoa, Sorim! That sounds incredible!","TWN":"哇～蕭林，你竟然能說出這種大道理。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훗, 본관은 베테랑. 이런 지혜 또한 산전수전을 거친 경험의 산물이라고 할 수 있다.","JPN":"フフッ、本官はベテランだ。\\nこのような知恵もまた、長年にわたる豊富な経験の産物と言えるだろう。","ENG":"Heh. I'm a veteran. I've gained such wisdom during years of hardship I've gone through.","TWN":"哼哼，本官好歹也是征戰無數的沙場老將，當然也累積不少人生智慧跟經驗。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"똑똑한 소림이 말이 맞아. 우리가 너무 먼 곳에서 답을 찾으려고 했던 것 같아.","JPN":"ミズキちゃんの言う通りだよ。私たちは考えすぎて、\\n手の届かないところで答えを探そうとしていたのかもしれない。","ENG":"I agree with smart Sorim. Perhaps we were looking too far away for the answer.","TWN":"有智慧的蕭林說的沒錯！我們有點本末倒置了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"호, 호진 언니. 그렇게까지 칭찬하면 부끄러운데……","JPN":"そ、そんなに褒められると照れてしまう……","ENG":"H-Hojin, you flatter me so much...","TWN":"鎬…鎬眞姐，你這樣一直誇我，我會害羞……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"고양이가 키워질 환경이나 주인 같은 건 중요하지 않아!","JPN":"猫を飼う環境や飼い主より、大事なものがあります！","ENG":"It doesn't matter what kind of environment the cat will be raised in or who will raise him.","TWN":"養貓的重點不是環境或主人！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"맞아요. 환경보다 중요한 건, 마음이죠!","JPN":"そうです。環境より大事なのは、気持ちです！","ENG":"No. What matters more than the environment is the heart.","TWN":"沒錯！比起那些，更重要的是心！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응! 이제 더는 조건을 따지지 말고 고양이와 마음이 통하는 사람을 찾아보자!","JPN":"うん！　もう条件より、猫ちゃんと心が通じる人を探そう！","ENG":"That's right! Let's stop being so picky and find someone who can really love Maximus.","TWN":"沒錯！我們就放棄那些所謂的條件，找個能和貓咪合得來的人吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 여전히 문제가 있다. 그런 사람을 어디서 찾지?","JPN":"しかしまだ問題がある。どこで探せばいいんだ？","ENG":"But here's the problem: where can we find them?","TWN":"但還是有問題欸？那種人要去哪找？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"우리가 키우면 돼! 어떻게든 비용을 마련해서 고양이가 따로 지낼 수 있는 공간을 마련해보자.","JPN":"私たちが飼えばいいの！\\nなんとかお金を用意して、猫ちゃんが過ごせる場所を用意してみよう。","ENG":"We don't have to. We can raise him. We'll get money, somehow, to create a separate place for him in the clubhouse.","TWN":"不用找了，就是我們！我們就想辦法弄點經費幫貓咪弄個家吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>막시무스</color>가 우릴 부담스러워하지만 않는다면 말이야.","JPN":"<color=#ffd34c>マクシムス</color>が私たちでもよければの話だけど。","ENG":"If <color=#ffd34c>Maximus</color> wants to stay with us, that is.","TWN":"只要<color=#ffd34c>咖啡貓</color>不討厭我們的話！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"... Okay.","TWN":"……嗯。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자! 그럼 이제 아카데미로 돌아가서 새 동료를 받아들일 준비를……","JPN":"さて！　アカデミーに戻って新しい家族を迎え入れる準備を……","ENG":"Alright, then let's go back to the Academy and get ready for our new companion—","TWN":"既然都決定好了，我們就回去學院開始新夥伴入住的準備工作吧……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Err?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"길 건너에 익숙한 복장의 사람이 있는데요?","JPN":"向こうに見慣れた制服の人がいます！","ENG":"There's someone in familiar-looking clothes on the other side of the street.","TWN":"對面有位衣服很眼熟的人？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"そうですね。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"환경이 아닌 마음을 따른다.","JPN":"環境ではなく、心に従う。","ENG":"Following the heart instead of the environment.","TWN":"環境不是重點，重點是心！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"불합리한 조건에도 흐르는 물처럼 자신을 바꿔나가는 것이 중요하죠.","JPN":"不合理な条件でも、流水のように自分を変えていくことが重要です。","ENG":"You must change yourself, like moving water does, no matter how tough it is.","TWN":"重點是要保持彈性，不墨守成規。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후배님들에게 한 수 배웠어요.","JPN":"この度は後輩から、また一つ教わりました。","ENG":"Thank you for the lesson, juniors.","TWN":"你們給我上了一課呢！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"앗, 사부! 어떻게 알고 오셨어요? 안 그래도 사부에게 할 말이……","JPN":"あれ、師匠？　こちらにはどうやって？　ちょうど報告したいことが……","ENG":"Ah, Master! How did you know we were here? Actually, we've got something to tell you.","TWN":"嗯？你怎麼會來？我們正好有話要跟你說……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 또한 화이트래빗 여러분에게 하고 싶은 말이 있답니다.","JPN":"私もホワイトラビットの皆さんに話したいことがあります。","ENG":"I too have something to tell you, White Rabbits.","TWN":"我也有話要跟白兔社的大家說。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 저희에게 볼일이요?","JPN":"はい？　私たちに、ですか？","ENG":"Sorry? To us?","TWN":"嗯？找我們有事嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마음의 평온이라 함은, 자신의 안전을 확신했을 때 얻을 수 있는 것.","JPN":"心の安らぎとは、自身の安全を確信した時に得られるもの。","ENG":"One can never find peace of mind unless he's assured of his safety.","TWN":"所謂心裡的平安呢，是在你確定自己是安全時才會得到的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"란체스터 2세의 상냥한 마음씨와 부드러운 털을 지켜줄 수 있는 사람이야말로 주인으로서 적격이라고 할 수 있겠죠.","JPN":"ランチェスター2世の優しい心と柔らかい毛を守ってあげられる人間こそ、\\n飼い主の資格があると言えるでしょう。","ENG":"I believe Lanchester II must go to live with someone who can protect his kind heart and soft fur.","TWN":"要能夠守護蘭賈斯特二世的善良和柔軟的毛，才夠資格當牠的主人！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"뭔가 분위기가 이상하다.","JPN":"なんか雰囲気が変わってしまった……？","ENG":"Err, where is this going?","TWN":"她怎麼好像怪怪的？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어… 왠지 사부의 눈빛이 최면에 걸린 나이엘처럼 변했어.","JPN":"あれ……なんだか師匠の目が催眠術にかかったナイエルみたいになっている……","ENG":"Ack, the Master's eyes remind me of Naielle when she was hypnotized.","TWN":"嗯…眼神好像不太對勁，是被催眠嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 학생회장으로서, 다시 한 번 제가 란체스터 2세를 키울 자격에 도전하겠습니다.","JPN":"アカデミーの生徒会長として、私がもう一度ランチェスター2世の飼い主になる資格に挑ませていただきます。","ENG":"As the Student President of the Academy, I'd like to plead with you to give me another chance at becoming Lanchester II's owner.","TWN":"我身為學院的學生會長，決定要再次挑戰成為蘭賈斯特二世主人的資格賽！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 하지만 학생회 일이 바빠서 키우기엔 무리라고 하지 않으셨어요?","JPN":"え？　でも、生徒会の仕事が忙しすぎて猫を飼うのは難しいって言いましたよね？","ENG":"Sorry? But you said you're too busy running the Council to raise him.","TWN":"可是，你不是說學生會很忙你無法養嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그때의 저는 분명 그렇게 말했었죠.","JPN":"あの時の私は確かにそう言いました。","ENG":"At that time, I thought I was.","TWN":"沒錯，我是那麼說過。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어리석게도… 나 자신을 바꿀 생각은 하지 못한 채 현실의 환경에 굴복해버린 거에요.","JPN":"愚かにも……自分自身を変えようともせず、現実の環境に屈してしまったのです。","ENG":"Instead of thinking about changing myself, I foolishly let my situation dominate me.","TWN":"我真是愚蠢…我沒有改變我的想法，而是屈服於現實的環境。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 아카데미 학생들의 모범이 되어야 할 한 사람으로서, 이렇게 딱딱한 모습을 보여선 곤란하겠죠.","JPN":"しかし、アカデミーの生徒の模範となるべき者として、\\nこんな姿を見せてはいけないと思いました。","ENG":"But as someone who should set a good example to the rest of the Academy, I mustn't be so inflexible.","TWN":"身為學生會長，我應該要成為學生的榜樣，怎麼可以讓學生看到我這副不知變通的模樣呢！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자, 란체스터 2세를 지켜줄 수 있는 사람으로 누가 적격일지.","JPN":"さあ、ランチェスター2世を守れる人として誰が適格なのか。","ENG":"Now, let's see who can protect Lanchester II the best","TWN":"來吧！誰才是可以守護蘭賈斯特二世的人？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금 당장 결투를 통해 시험해보도록 하죠.","JPN":"今すぐ決闘を通じて、確かめましょう。","ENG":"by fighting right here and now.","TWN":"現在就立刻分個勝負吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자, 잠깐만요! 진정하세요, 사부! 고양이는 그냥 저희가 키워도 괜찮을 것 같은데……","JPN":"ま、待ってください、師匠！　猫ちゃんは私たちが飼うとさっき……","ENG":"H-hang on! Calm down, Master! We can take care of the cat.","TWN":"欸，你等一下啦！你先別急，貓咪我們可以養啦…"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨! 학생회장의 권한으로, 결투를 신청합니다!","JPN":"いいえ！　生徒会長の権限において、決闘を申し込みます！","ENG":"Nope! With my authority as Student President, I challenge you to a duel!","TWN":"拒絕！以我學生會長的身份命令你們跟我打！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"란체스터 2세를 데려가고 싶다면 저를 먼저 꺾어야 할 거예요.","JPN":"ランチェスター2世を連れていきたいなら、まずはこの私を倒してください。","ENG":"If you want to keep Lanchester II, then you'll have to beat me first.","TWN":"你們想帶走蘭賈斯特二世的話，就必須先過我這一關！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네?! 그, 그거 직권 남용… 뭐 그런 거 아니에요?","JPN":"えっ！？　そ、それって職権乱用……みたいなものなのでは？","ENG":"What? I-isn't this abuse of authority?","TWN":"欸？！這是濫用職權吧…不是這樣的吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"곧 데리러가겠어요, 란체스터 2세.","JPN":"すぐ迎えに行きます、ランチェスター2世。","ENG":"I'll come for you soon, Lanchester II.","TWN":" 蘭賈斯特二世你等我，我很快就會把你帶回家！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"…야옹?","JPN":"……ニャ？","ENG":"Meow?","TWN":"…喵喵？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으으, 어떻게 하지 하림아? 사부 눈빛이 완전 진심인데?","JPN":"ええ……どうしようウサギちゃん。\\n師匠の目が……完全に本気モードになっている！","ENG":"Aww, what do we do, Harim? The Master means business.","TWN":"夏琳，怎麼辦？她的眼神好像是認真的？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"알겠어요, 회장님. 승부해요!","JPN":"わかりました、会長。勝負しましょう！","ENG":"Very well, President. Let's duel!","TWN":"好吧，那我們就來分個勝負吧！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하, 하림 언니?","JPN":"ウ、ウサギ隊長？","ENG":"H-Harim?","TWN":"夏…夏琳姐？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"회장님의 마음은 잘 알겠지만, 우리의 마음도 거기에 지지 않아!","JPN":"会長の気持ちはわかりましたが、私たちだって気持ちの面では負けてないから！","ENG":"As much as you want him, we want him, too!","TWN":"會長那麼認真看待這件事，我們當然也要認真看待！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"응해주셔서 감사합니다, 여러분.","JPN":"応じてくれてありがとうございます。","ENG":"Thank you for accepting my challenge, everyone.","TWN":"謝謝大家的體諒。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분이 이긴다면 란체스터 2세의 생활에 필요한 모든 비용과 환경을 제공하도록 하겠습니다.","JPN":"皆さんが勝ったら、ランチェスター2世が快適に過ごすために必要なすべての費用と環境を提供します。","ENG":"If you win, I'll provide you with the money and environment you need to take care of Lanchester II.","TWN":"你們贏的話，蘭賈斯特二世需要的一切費用和環境就由我來提供！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 여러분이 패배한다면, 란체스터 2세는 제가 책임지도록 하죠. 납득하셨나요?","JPN":"皆さんが負けたら、ランチェスター2世は私が責任を持って飼うことにします。\\nよろしいですね？","ENG":"But if you lose, I'll take care of Lanchester II myself. Do you agree?","TWN":"但要是你們輸的話，蘭賈斯特二世就要歸我！這樣可以嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"뭔가 자연스러운 전개인 척 하고 있긴 하지만…… 정말 이래도 괜찮은 걸까?","JPN":"なんか自然とこういう展開になってしまったけど……本当にいいのかな？","ENG":"I'm playing along for now, but... should we really do this?","TWN":"雖然我正努力把現在的情況看作是正常的…但真的要打嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아니, 생각해보면 어느 쪽이 이기든 고양이에겐 잘된 일일 지도?","JPN":"あ、でもどっちが勝っても猫ちゃんにとっていいことなのかな？","ENG":"Well, but then again, whoever wins, it's good for the cat.","TWN":"不，仔細想想，不管哪一方贏，對貓咪應該都是好事吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"각오를 다져라, 호진 대원. 이 싸움이 막시무스 이병 구하기의 마지막 클라이막스다!","JPN":"覚悟を決めるのだ、マユミ隊員。これがマクシムス二等兵救出のための最後の戦いとなる！","ENG":"Brace yourself, Operative Hojin. This fight is going to be the climax of Saving Private Maximus.","TWN":"鎬眞隊員，下定決心吧！這是救援咖啡貓二等兵的最終戰！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"알겠어요! 누가 더 고양이를 사랑하고 아껴주는지 승부에요!","JPN":"わかりました！　どっちがもっと猫ちゃんを可愛がってあげられるか勝負です！","ENG":"Got it! Let's find out who loves cats more than the other!","TWN":"來吧！誰才是真正愛貓的人！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};